import { type, type Type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

/**
 * Export an ArkType schema to a JSON Schema document (draft-2020-12).
 *
 * The returned object contains the `$schema` field set to the draft-2020-12 URI.
 */
export function exportJsonSchema(schema: Type): object {
  const jsonSchema = schema.toJsonSchema()
  // toJsonSchema already includes $schema when called with default options,
  // but ensure it's present for the contract.
  if (!("$schema" in jsonSchema)) {
    ;(jsonSchema as Record<string, unknown>).$schema =
      "https://json-schema.org/draft/2020-12/schema"
  }
  return jsonSchema
}

/**
 * Round-trip an ArkType schema through JSON Schema and back.
 *
 * 1. Export `schema` to JSON Schema (draft-2020-12) via `schema.toJsonSchema()`.
 * 2. Re-parse the resulting JSON Schema back into an ArkType `Type` using
 *    `@ark/json-schema`'s `jsonSchemaToType`.
 * 3. Return the re-parsed Type.
 */
export function roundTrip(schema: Type): Type {
  const jsonSchema = exportJsonSchema(schema)
  // jsonSchemaToType returns a Type from @ark/json-schema's bundled arktype.
  // The returned type is callable and behaves as a Type.
  return jsonSchemaToType(jsonSchema) as Type
}

import { type } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.ts"

interface Input {
  schema: unknown
  corpus: unknown[]
}

interface Agreement {
  index: number
  originalAccept: boolean
  roundTrippedAccept: boolean
  agree: boolean
}

interface Output {
  jsonSchema: object
  agreements: Agreement[]
  allAgree: boolean
}

async function main(): Promise<void> {
  // Read stdin
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.from(chunk))
  }
  const inputJson = Buffer.concat(chunks).toString("utf-8")
  const input: Input = JSON.parse(inputJson)

  // Build the original Type from the definition
  const original = type(input.schema as any)

  // Obtain the JSON Schema and round-tripped Type
  const jsonSchema = exportJsonSchema(original)
  const roundTripped = roundTrip(original)

  // Test each payload in the corpus
  const agreements: Agreement[] = []
  let allAgree = true

  for (let i = 0; i < input.corpus.length; i++) {
    const payload = input.corpus[i]

    // original(payload) returns either the validated data or an ArkErrors instance
    const originalResult = original(payload)
    // An ArkErrors instance means rejection; otherwise it was accepted
    const originalAccept = !(originalResult instanceof type.errors)

    const roundTrippedResult = roundTripped(payload)
    const roundTrippedAccept = !(roundTrippedResult instanceof type.errors)

    const agree = originalAccept === roundTrippedAccept
    if (!agree) {
      allAgree = false
    }

    agreements.push({
      index: i,
      originalAccept,
      roundTrippedAccept,
      agree,
    })
  }

  const output: Output = {
    jsonSchema,
    agreements,
    allAgree,
  }

  process.stdout.write(JSON.stringify(output) + "\n")

  if (!allAgree) {
    process.exit(1)
  }
}

main().catch((err) => {
  console.error(err)
  process.exit(1)
})

